// Sabores de Sudamérica — datos de recetas
// Para agregar o editar recetas, modifica los objetos de este arreglo.
const RECETAS = [
{id:"ar-01",pais:"Argentina",nombre:"Asado con chimichurri",desc:"El rito argentino por excelencia: cortes de res cocidos lentamente sobre brasas y acompañados de chimichurri fresco.",tiempo:150,porciones:6,dificultad:"Media",ingredientes:["2 kg de tira de asado","1 kg de vacío","Sal gruesa","1 taza de perejil picado","4 dientes de ajo picados","1 cda de orégano seco","1 cdita de ají molido","1/2 taza de aceite de oliva","1/4 taza de vinagre de vino","1/4 taza de agua tibia"],pasos:["Prepara el chimichurri mezclando perejil, ajo, orégano, ají molido, vinagre, agua y aceite; deja reposar al menos 1 hora.","Enciende el fuego con leña o carbón y espera a tener brasas parejas, sin llama.","Sala la carne con sal gruesa por ambos lados.","Coloca la tira de asado con el hueso hacia abajo y cocina a fuego suave 60–80 minutos.","Da vuelta los cortes y termina la cocción hasta que estén dorados por fuera y jugosos por dentro.","Sirve recién cortado con chimichurri por encima."],ilu:{t:"plato",c:["#8C4A32","#5C8A4E","#C0392B"]}},
{id:"ar-02",pais:"Argentina",nombre:"Empanadas criollas",desc:"Empanadas de carne cortada a cuchillo con cebolla, huevo y aceitunas, horneadas hasta dorar.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["500 g de carne de res picada a cuchillo","2 cebollas picadas","1 cebolla de verdeo","2 huevos duros picados","12 aceitunas verdes","1 cdita de comino","1 cda de pimentón dulce","Sal y pimienta","12 tapas de empanada para horno","1 huevo batido para pintar"],pasos:["Rehoga la cebolla en un poco de grasa o aceite hasta que esté transparente.","Agrega la carne, el comino y el pimentón; cocina 10 minutos y salpimienta.","Deja enfriar el relleno y mezcla con el huevo duro, la aceituna y el verdeo.","Rellena las tapas, humedece los bordes y cierra con repulgue.","Pinta con huevo batido y hornea a 220 °C por 15–18 minutos hasta dorar.","Sirve calientes, idealmente acompañadas de un buen vino tinto."],ilu:{t:"empanada",c:["#E3B23C","#C98B2D","#8C4A32"]}},
{id:"ar-03",pais:"Argentina",nombre:"Milanesa a la napolitana",desc:"Milanesa de res cubierta con salsa de tomate, jamón y queso gratinado: un clásico de bodegón.",tiempo:45,porciones:4,dificultad:"Fácil",ingredientes:["4 filetes de nalga o bola de lomo","2 huevos","2 dientes de ajo picados","Perejil picado","300 g de pan rallado","1 taza de salsa de tomate","4 fetas de jamón cocido","200 g de muzzarella","Aceite para freír","Sal y pimienta"],pasos:["Bate los huevos con ajo, perejil, sal y pimienta.","Pasa los filetes por el huevo y luego por pan rallado, presionando bien.","Fríe las milanesas en aceite caliente hasta dorar y escurre sobre papel.","Cubre cada milanesa con salsa de tomate, jamón y muzzarella.","Gratina en horno fuerte 5–8 minutos hasta fundir el queso.","Sirve con papas fritas o puré."],ilu:{t:"plato",c:["#D9A05B","#C0392B","#F2E3C2"]}},
{id:"ar-04",pais:"Argentina",nombre:"Locro",desc:"Guiso espeso de maíz blanco, porotos, zapallo y carnes, infaltable en las fiestas patrias.",tiempo:180,porciones:8,dificultad:"Alta",ingredientes:["500 g de maíz blanco pisado (remojado desde la víspera)","250 g de porotos pallares (remojados)","500 g de falda de res","2 chorizos","150 g de panceta","500 g de zapallo en cubos","1 cebolla","2 cebollas de verdeo","1 cda de pimentón","1 cdita de ají molido"],pasos:["Hierve el maíz y los porotos escurridos en abundante agua durante 1 hora.","Agrega la falda, la panceta y el chorizo en trozos; cocina 1 hora más a fuego bajo.","Suma el zapallo y la cebolla picada y cocina hasta que el guiso espese, revolviendo para que no se pegue.","Prepara la salsa picante: rehoga verdeo con pimentón y ají molido en aceite.","Ajusta la sal y sirve bien caliente con un chorrito de la salsa por encima."],ilu:{t:"bowl",c:["#DD8436","#EFC94C","#5C8A4E"]}},
{id:"ar-05",pais:"Argentina",nombre:"Provoleta",desc:"Queso provolone dorado a la parrilla con orégano y ají molido, la entrada favorita del asado.",tiempo:20,porciones:4,dificultad:"Fácil",ingredientes:["4 rodajas gruesas de queso provolone (2 cm)","1 cda de orégano seco","1 cdita de ají molido","Aceite de oliva","Pan crocante para acompañar"],pasos:["Deja orear el queso 1 hora a temperatura ambiente para que forme costra al cocinarse.","Calienta bien la plancha o provoletera sobre las brasas.","Coloca el queso y cocina sin moverlo hasta que dore la base.","Da vuelta con cuidado, espolvorea orégano y ají molido.","Retira cuando esté fundido por dentro y crocante por fuera; sirve de inmediato con pan."],ilu:{t:"plato",c:["#F2E3C2","#E3B23C","#5C8A4E"]}},
{id:"ar-06",pais:"Argentina",nombre:"Choripán",desc:"Chorizo a la parrilla en pan crocante con chimichurri: el sándwich callejero argentino.",tiempo:30,porciones:4,dificultad:"Fácil",ingredientes:["4 chorizos de cerdo","4 panes tipo baguette chica","Chimichurri","Salsa criolla (tomate, cebolla, morrón, vinagre)"],pasos:["Cocina los chorizos a fuego medio en la parrilla unos 20 minutos, girándolos.","Ábrelos al medio (mariposa) y dóralos 2 minutos por el corte.","Tuesta levemente el pan sobre la parrilla.","Arma el sándwich con el chorizo y abundante chimichurri o salsa criolla.","Sirve caliente, sin cubiertos y sin culpa."],ilu:{t:"sandwich",c:["#D9A05B","#8C4A32","#5C8A4E"]}},
{id:"ar-07",pais:"Argentina",nombre:"Humita en chala",desc:"Pasta cremosa de choclo y albahaca envuelta en hojas de maíz y cocida al vapor.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["8 choclos con sus hojas (chalas)","1 cebolla picada","1 morrón rojo picado","Hojas de albahaca","100 g de queso cremoso (opcional)","1 cdita de pimentón","Leche (si hace falta aligerar)","Sal y pimienta"],pasos:["Reserva las chalas más grandes y ralla o procesa los granos de choclo.","Rehoga cebolla y morrón, agrega el choclo y cocina hasta obtener una pasta cremosa.","Perfuma con albahaca, pimentón, sal y pimienta; añade queso si quieres.","Arma paquetes con dos chalas encontradas, rellena y ata con tiras de chala.","Cocina al vapor o en agua apenas hirviendo 30–40 minutos y sirve tibias."],ilu:{t:"envuelto",c:["#9DBE6E","#EFC94C","#5C8A4E"]}},
{id:"ar-08",pais:"Argentina",nombre:"Carbonada criolla",desc:"Guiso de carne, zapallo, choclo y duraznos, dulce y salado a la vez, típico del norte.",tiempo:100,porciones:6,dificultad:"Media",ingredientes:["800 g de carne de res en cubos","1 cebolla","1 morrón","2 tomates","500 g de zapallo en cubos","2 papas","2 batatas","2 choclos en rodajas","100 g de orejones de durazno","1 litro de caldo"],pasos:["Dora la carne en una olla con un poco de aceite y reserva.","En la misma olla rehoga cebolla, morrón y tomate picados.","Vuelve la carne, cubre con caldo y cocina 40 minutos a fuego bajo.","Agrega papa, batata, zapallo y choclo; cocina 20 minutos más.","Suma los orejones, rectifica la sal y cocina hasta que todo esté tierno.","Sirve bien caliente, tradicionalmente dentro de un zapallo ahuecado."],ilu:{t:"bowl",c:["#C9762B","#EFC94C","#DD8436"]}},
{id:"ar-09",pais:"Argentina",nombre:"Alfajores de maicena",desc:"Tapas que se deshacen en la boca, unidas con dulce de leche y bordeadas de coco rallado.",tiempo:75,porciones:12,dificultad:"Media",ingredientes:["300 g de maicena","200 g de harina","200 g de manteca","150 g de azúcar","3 yemas","Ralladura de 1 limón","1 cdita de esencia de vainilla","400 g de dulce de leche repostero","Coco rallado"],pasos:["Bate la manteca con el azúcar hasta cremar; agrega yemas, vainilla y ralladura.","Incorpora maicena y harina tamizadas hasta formar una masa suave; refrigera 30 minutos.","Estira de 5 mm y corta discos; hornea a 170 °C por 10–12 minutos sin que doren.","Deja enfriar por completo (las tapas son muy frágiles).","Une de a pares con abundante dulce de leche y haz rodar los bordes por coco rallado."],ilu:{t:"pan",c:["#F2E3C2","#FFFFFF","#C98B2D"]}},
{id:"ar-10",pais:"Argentina",nombre:"Pastelitos criollos",desc:"Hojaldres rellenos de dulce de membrillo, fritos y bañados en almíbar, clásicos del 25 de Mayo.",tiempo:80,porciones:8,dificultad:"Media",ingredientes:["500 g de harina","100 g de grasa o manteca (más extra para hojaldrar)","Agua con sal cantidad necesaria","300 g de dulce de membrillo","Grasa o aceite para freír","200 g de azúcar para el almíbar","Granas de colores (opcional)"],pasos:["Forma una masa lisa con harina, grasa y agua con sal; deja descansar 20 minutos.","Estira fino, unta con grasa, dobla en capas y repite dos veces para hojaldrar.","Corta cuadrados, coloca un cubo de membrillo y cierra con otro cuadrado girado, uniendo las puntas.","Fríe primero en grasa tibia para abrir el hojaldre y luego en caliente para dorar.","Baña con almíbar liviano y decora con granas antes de servir."],ilu:{t:"pan",c:["#E8C36A","#C0392B","#F2E3C2"]}},
{id:"bo-01",pais:"Bolivia",nombre:"Salteñas",desc:"Empanadas horneadas de masa dulce con relleno jugoso de carne y caldo gelatinizado.",tiempo:180,porciones:8,dificultad:"Alta",ingredientes:["500 g de harina","100 g de manteca","2 cdas de azúcar","1 cdita de achiote molido","400 g de pollo o carne de res cocida y desmenuzada","2 papas cocidas en cubos","1/2 taza de arvejas","1 cebolla picada","2 cdas de ají amarillo molido","2 tazas de caldo con 1 cda de gelatina sin sabor","Huevo duro y aceitunas"],pasos:["Prepara el jigote: rehoga cebolla con ají y achiote, agrega carne, papa, arvejas y el caldo con gelatina; enfría hasta que cuaje.","Haz la masa con harina, manteca, azúcar, achiote y agua tibia; deja reposar.","Estira discos de masa y rellena con el jigote frío, un trozo de huevo y aceituna.","Cierra con repulgue hacia arriba, formando la cresta característica.","Hornea a 250 °C por 12–15 minutos hasta que brillen.","Sirve calientes y cómelas de pie: el caldo interior es traicionero."],ilu:{t:"empanada",c:["#DD8436","#B0532F","#8C4A32"]}},
{id:"bo-02",pais:"Bolivia",nombre:"Pique macho",desc:"Montaña de carne, salchicha y papas fritas con cebolla, tomate y locoto: plato para compartir.",tiempo:60,porciones:4,dificultad:"Media",ingredientes:["500 g de lomo de res en cubos","2 salchichas en rodajas","4 papas grandes para freír","1 cebolla en pluma","2 tomates en gajos","1 locoto en tiras","2 huevos duros","2 cdas de mostaza","2 cdas de kétchup","Salsa de soya y cerveza negra (un chorro)"],pasos:["Fríe las papas en bastones gruesos y resérvalas calientes.","Saltea la carne a fuego fuerte hasta dorar; agrega la salchicha.","Suma cebolla, tomate y locoto; saltea 3 minutos para que queden crocantes.","Sazona con mostaza, kétchup, soya y un chorro de cerveza; deja reducir.","Sirve la mezcla sobre las papas y corona con huevo duro en rodajas."],ilu:{t:"plato",c:["#8C4A32","#E3B23C","#C0392B"]}},
{id:"bo-03",pais:"Bolivia",nombre:"Silpancho",desc:"Carne apanada extendida y delgada sobre arroz y papas, coronada con huevo frito y sarsa.",tiempo:50,porciones:4,dificultad:"Media",ingredientes:["4 filetes de res","2 tazas de pan molido","2 tazas de arroz cocido","4 papas cocidas en rodajas","4 huevos","1 cebolla picada fina","2 tomates picados","1 locoto picado (opcional)","Vinagre, sal y pimienta","Aceite para freír"],pasos:["Apana los filetes con pan molido y mártalos hasta dejarlos muy delgados y grandes.","Fríe las rodajas de papa hasta dorar y reserva.","Fríe los silpanchos 1–2 minutos por lado en aceite caliente.","Prepara la sarsa mezclando cebolla, tomate y locoto con vinagre y sal.","Sirve sobre una cama de arroz y papas, con huevo frito y sarsa encima."],ilu:{t:"plato",c:["#D9A05B","#EFC94C","#C0392B"]}},
{id:"bo-04",pais:"Bolivia",nombre:"Sopa de maní",desc:"Sopa cremosa de maní molido con carne y papas fritas por encima, orgullo cochabambino.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["1 taza de maní crudo pelado","500 g de carne de res con hueso","2 papas en bastones","1/2 taza de arvejas","1 zanahoria picada","1 cebolla picada","1/2 taza de fideo (opcional)","Orégano y comino","Perejil picado","Aceite para freír"],pasos:["Licúa el maní con un poco de agua hasta obtener una crema.","Hierve la carne con cebolla y zanahoria durante 40 minutos para hacer un caldo.","Agrega el maní licuado y cocina a fuego bajo 30 minutos, revolviendo para que no se pegue.","Suma arvejas y fideo, y cocina hasta que estén tiernos; sazona con orégano y comino.","Fríe los bastones de papa y colócalos encima de cada plato con perejil al servir."],ilu:{t:"bowl",c:["#E8C36A","#D9A05B","#5C8A4E"]}},
{id:"bo-05",pais:"Bolivia",nombre:"Chairo paceño",desc:"Sopa andina contundente de chuño, carne y mote, ideal para el frío del altiplano.",tiempo:120,porciones:6,dificultad:"Media",ingredientes:["1 taza de chuño remojado y martajado","400 g de carne de res","200 g de carne de cordero","1 taza de mote de maíz cocido","2 papas en cubos","1 zanahoria","1/2 taza de habas","1 cebolla","1 ramita de hierbabuena","Orégano y sal"],pasos:["Hierve las carnes en abundante agua con cebolla durante 45 minutos.","Agrega el chuño martajado y cocina 20 minutos.","Suma papa, zanahoria, habas y mote; cocina hasta que todo esté tierno.","Sazona con orégano y sal, y perfuma con hierbabuena al final.","Sirve bien caliente con la carne en trozos en cada plato."],ilu:{t:"bowl",c:["#C9A36A","#8C6A4A","#5C8A4E"]}},
{id:"bo-06",pais:"Bolivia",nombre:"Fricasé paceño",desc:"Caldo picante de cerdo con ají amarillo, mote y chuño, famoso por revivir a cualquiera.",tiempo:150,porciones:6,dificultad:"Alta",ingredientes:["1 kg de cerdo en trozos (costilla y carne)","4 cdas de ají amarillo molido","4 dientes de ajo","1 cdita de comino","1 cdita de orégano","1/2 taza de pan molido","2 tazas de mote cocido","6 chuños cocidos","Cebolla verde picada","Sal y pimienta"],pasos:["Sofríe el ají amarillo con ajo, comino y orégano en un poco de aceite.","Agrega el cerdo, cubre con agua caliente y cocina a fuego bajo 1,5 a 2 horas hasta que esté muy tierno.","Espesa ligeramente el caldo con pan molido disuelto, revolviendo.","Rectifica la sal: el caldo debe quedar picante y sustancioso.","Sirve cada plato con mote, chuño y cebolla verde por encima."],ilu:{t:"bowl",c:["#E3A23B","#F2E3C2","#5C8A4E"]}},
{id:"bo-07",pais:"Bolivia",nombre:"Majadito cruceño",desc:"Arroz colorado con charque deshilachado, plátano frito y huevo, emblema del oriente boliviano.",tiempo:70,porciones:4,dificultad:"Media",ingredientes:["300 g de charque (carne seca) o falda","2 tazas de arroz","1 cebolla picada","1 tomate picado","1 pimentón picado","1 cdita de urucú (achiote)","2 plátanos maduros","4 huevos","Yuca cocida (opcional)","Sal"],pasos:["Hierve el charque para desalar, luego deshiláchalo y dóralo en sartén.","Sofríe cebolla, tomate y pimentón con el urucú disuelto en aceite.","Agrega el arroz y el charque, cubre con agua caliente y cocina hasta que el arroz esté a punto.","Fríe los plátanos en rodajas y los huevos.","Sirve el majadito con plátano frito y huevo encima de cada porción."],ilu:{t:"plato",c:["#D98436","#8C4A32","#EFC94C"]}},
{id:"bo-08",pais:"Bolivia",nombre:"Sajta de pollo",desc:"Pollo bañado en salsa de ají amarillo servido con papa, chuño y sarsa de cebolla.",tiempo:80,porciones:4,dificultad:"Media",ingredientes:["4 presas de pollo","4 cdas de ají amarillo molido","1 cebolla picada","2 dientes de ajo","1 cdita de comino y orégano","4 papas cocidas","4 chuños cocidos (chuño phuti)","1 cebolla en pluma con tomate para la sarsa","Perejil picado","Sal"],pasos:["Cuece el pollo en agua con sal hasta que esté tierno; reserva el caldo.","Sofríe el ají amarillo con cebolla, ajo, comino y orégano.","Agrega caldo y el pollo, y cocina 15 minutos para que la salsa tome cuerpo.","Prepara la sarsa cruda con cebolla, tomate, sal y un toque de vinagre.","Sirve el pollo con su salsa, papa, chuño y la sarsa por encima."],ilu:{t:"plato",c:["#E3A23B","#F2E3C2","#C0392B"]}},
{id:"bo-09",pais:"Bolivia",nombre:"Cuñapés",desc:"Panecillos de almidón de yuca y queso, crocantes por fuera y elásticos por dentro.",tiempo:40,porciones:6,dificultad:"Fácil",ingredientes:["2 tazas de almidón de yuca","2 tazas de queso semiduro rallado","1 huevo","2 cdas de mantequilla","Leche cantidad necesaria","1 pizca de sal"],pasos:["Mezcla el almidón con el queso, la sal, el huevo y la mantequilla.","Agrega leche de a poco hasta lograr una masa suave que no se pegue.","Forma bolitas del tamaño de una nuez grande.","Hornea a 200 °C por 15–18 minutos hasta que doren apenas.","Sírvelos tibios, idealmente con un café o un api."],ilu:{t:"pan",c:["#E8C36A","#FFF6E3","#C98B2D"]}},
{id:"bo-10",pais:"Bolivia",nombre:"Api morado con pastel",desc:"Bebida caliente y espesa de maíz morado con canela, acompañada de pastel de queso frito.",tiempo:45,porciones:4,dificultad:"Fácil",ingredientes:["1 taza de harina de maíz morado","6 tazas de agua","1 rama de canela","3 clavos de olor","Azúcar al gusto","Jugo de 1 limón","4 láminas de masa de empanada grande","150 g de queso fresco","Aceite para freír","Azúcar impalpable"],pasos:["Disuelve la harina de maíz morado en agua fría.","Hierve con canela y clavo, revolviendo 20 minutos hasta espesar.","Endulza y agrega el jugo de limón para avivar el color.","Rellena las láminas de masa con queso, cierra y fríe hasta inflar y dorar.","Espolvorea el pastel con azúcar impalpable y sirve junto al api bien caliente."],ilu:{t:"taza",c:["#6E4585","#F2E3C2","#FFF6E3"]}},
{id:"br-01",pais:"Brasil",nombre:"Feijoada",desc:"El guiso nacional brasileño: frijoles negros con carnes de cerdo, servido con arroz, farofa y naranja.",tiempo:180,porciones:8,dificultad:"Alta",ingredientes:["500 g de frijoles negros (remojados)","300 g de costilla de cerdo salada (desalada)","200 g de tocino","2 chorizos paio o ahumados","300 g de carne seca (desalada)","1 cebolla","4 dientes de ajo","2 hojas de laurel","Arroz blanco, farofa y col salteada para acompañar","2 naranjas en gajos"],pasos:["Desala las carnes desde la víspera cambiando el agua varias veces.","Cocina los frijoles con laurel en abundante agua durante 1 hora.","Agrega las carnes en trozos y cocina 1 hora más a fuego bajo.","Sofríe cebolla y ajo, incorpora un cucharón de frijoles machacados y devuelve todo a la olla para espesar.","Cocina hasta que el caldo esté denso y las carnes muy tiernas.","Sirve con arroz, farofa, col y naranja, que aligera el plato."],ilu:{t:"bowl",c:["#3A2E2A","#8C4A32","#DD8436"]}},
{id:"br-02",pais:"Brasil",nombre:"Moqueca baiana",desc:"Pescado cocido en leche de coco, aceite de dendê y pimentones, servido burbujeante en cazuela.",tiempo:60,porciones:4,dificultad:"Media",ingredientes:["800 g de pescado blanco firme en postas","Jugo de 2 limones","3 dientes de ajo","1 cebolla en aros","1 pimentón rojo y 1 verde en aros","2 tomates en rodajas","400 ml de leche de coco","2 cdas de aceite de dendê","Cilantro fresco","Sal y pimienta"],pasos:["Marina el pescado con limón, ajo, sal y pimienta por 30 minutos.","En una cazuela acomoda capas de cebolla, pimentón y tomate, y el pescado encima.","Vierte la leche de coco y cocina tapado a fuego medio 15 minutos sin revolver.","Agrega el aceite de dendê y cocina 5 minutos más.","Termina con abundante cilantro y sirve con arroz blanco o pirão."],ilu:{t:"pescado",c:["#E0863B","#C95B39","#5C8A4E"]}},
{id:"br-03",pais:"Brasil",nombre:"Pão de queijo",desc:"Panecillos de almidón de yuca y queso, dorados por fuera y chiclosos por dentro.",tiempo:50,porciones:6,dificultad:"Fácil",ingredientes:["500 g de polvilho (almidón de yuca agrio o dulce)","250 ml de leche","100 ml de aceite","2 huevos","250 g de queso semicurado rallado","1 cdita de sal"],pasos:["Hierve la leche con el aceite y la sal.","Vierte sobre el polvilho y mezcla hasta escaldar la masa; deja entibiar.","Incorpora los huevos uno a uno y luego el queso, amasando hasta integrar.","Forma bolitas con las manos aceitadas.","Hornea a 180 °C por 20–25 minutos hasta que doren; sírvelos calientes."],ilu:{t:"pan",c:["#E8C36A","#FFF6E3","#D9A05B"]}},
{id:"br-04",pais:"Brasil",nombre:"Coxinha",desc:"Croqueta en forma de gota rellena de pollo cremoso, empanizada y frita: reina de los botecos.",tiempo:90,porciones:8,dificultad:"Media",ingredientes:["2 pechugas de pollo","1 litro de caldo de pollo","500 g de harina de trigo","2 cdas de mantequilla","1 cebolla picada","2 dientes de ajo","100 g de queso crema (opcional)","2 huevos batidos","Pan molido","Aceite para freír"],pasos:["Cuece el pollo en el caldo, desmenúzalo y saltéalo con cebolla y ajo; mezcla con queso crema.","Hierve el caldo con mantequilla y agrega la harina de golpe, revolviendo hasta formar una masa lisa.","Deja entibiar la masa y amásala hasta que quede suave.","Toma porciones, rellena con el pollo y forma gotas cerrando hacia la punta.","Pasa por huevo y pan molido, y fríe en aceite caliente hasta dorar."],ilu:{t:"empanada",c:["#C98B2D","#A66A1F","#F2E3C2"]}},
{id:"br-05",pais:"Brasil",nombre:"Brigadeiros",desc:"Bolitas de chocolate y leche condensada cubiertas de granas, infaltables en todo cumpleaños.",tiempo:30,porciones:10,dificultad:"Fácil",ingredientes:["1 lata de leche condensada","3 cdas de cacao en polvo","1 cda de mantequilla","Granas de chocolate para cubrir"],pasos:["Mezcla la leche condensada, el cacao y la mantequilla en una olla.","Cocina a fuego bajo revolviendo siempre hasta que la mezcla se despegue del fondo (8–10 minutos).","Vierte en un plato engrasado y deja enfriar por completo.","Con las manos enmantequilladas forma bolitas.","Ruédalas por las granas y sírvelas en pirotines."],ilu:{t:"pan",c:["#5A3A2A","#3A2419","#8C5A3A"]}},
{id:"br-06",pais:"Brasil",nombre:"Acarajé",desc:"Buñuelo de frijol de ojo frito en dendê y relleno de vatapá y camarones, símbolo de Bahía.",tiempo:120,porciones:8,dificultad:"Alta",ingredientes:["500 g de frijol de ojo (caupí) remojado y pelado","1 cebolla","Sal","Aceite de dendê abundante para freír","Vatapá para rellenar","200 g de camarones secos o salteados","Ensalada de tomate y cilantro","Pimienta malagueta (opcional)"],pasos:["Frota los frijoles remojados para quitarles la piel por completo.","Procésalos con cebolla y sal hasta obtener una masa aireada; bátela para incorporar aire.","Calienta el dendê y fríe porciones de masa con forma ovalada hasta dorar.","Abre cada acarajé al medio como un pan.","Rellena con vatapá, camarones, ensalada y, si te atreves, malagueta."],ilu:{t:"arepa",c:["#C9692B","#E3A23B","#5C8A4E"]}},
{id:"br-07",pais:"Brasil",nombre:"Vatapá",desc:"Crema bahiana de pan, leche de coco, maní y camarón seco, perfumada con jengibre y dendê.",tiempo:60,porciones:6,dificultad:"Media",ingredientes:["4 panes del día anterior","400 ml de leche de coco","100 g de maní tostado","100 g de castañas de cajú (opcional)","150 g de camarón seco","1 cebolla","2 dientes de ajo","1 trozo de jengibre","3 cdas de aceite de dendê","Sal"],pasos:["Remoja el pan en la leche de coco hasta ablandar.","Licúa el pan con maní, castañas, camarón seco, cebolla, ajo y jengibre.","Vierte en una olla y cocina a fuego bajo revolviendo siempre.","Agrega el dendê y cocina hasta obtener una crema espesa y brillante.","Sirve caliente como acompañamiento de acarajé, arroz o pescados."],ilu:{t:"bowl",c:["#E0863B","#C9692B","#5C8A4E"]}},
{id:"br-08",pais:"Brasil",nombre:"Picanha asada",desc:"El corte más querido de Brasil, asado con su capa de grasa y apenas sal gruesa.",tiempo:50,porciones:6,dificultad:"Fácil",ingredientes:["1 picanha entera (1,2 kg aprox.) con su grasa","Sal gruesa","Farofa, arroz y vinagreta para acompañar"],pasos:["Corta la picanha en bifes gruesos siguiendo la fibra, manteniendo la grasa.","Sala generosamente con sal gruesa justo antes de asar.","Lleva a parrilla bien caliente con la grasa hacia arriba primero.","Sella ambos lados y termina la cocción a fuego medio al punto deseado.","Deja reposar 5 minutos, corta en láminas y sirve con farofa y vinagreta."],ilu:{t:"plato",c:["#8C4A32","#E8C36A","#5C8A4E"]}},
{id:"br-09",pais:"Brasil",nombre:"Caipirinha",desc:"El cóctel brasileño universal: cachaça, lima, azúcar y mucho hielo.",tiempo:10,porciones:2,dificultad:"Fácil",ingredientes:["2 limas","4 cditas de azúcar","100 ml de cachaça","Hielo en cubos abundante"],pasos:["Corta las limas en octavos quitando el corazón blanco para que no amargue.","Macera la lima con el azúcar en el vaso, presionando para extraer el jugo.","Llena el vaso con hielo.","Agrega la cachaça y revuelve bien de abajo hacia arriba.","Sirve de inmediato con una rodaja de lima."],ilu:{t:"vaso",c:["#CBD98A","#F2F7E3","#5C8A4E"]}},
{id:"br-10",pais:"Brasil",nombre:"Açaí en bowl",desc:"Pulpa helada de açaí batida con banana y servida con granola y fruta fresca.",tiempo:15,porciones:2,dificultad:"Fácil",ingredientes:["400 g de pulpa de açaí congelada","1 banana congelada","2 cdas de miel o jarabe de guaraná","1/2 taza de granola","Banana y frutillas en rodajas para decorar","Coco rallado (opcional)"],pasos:["Deja la pulpa de açaí 5 minutos fuera del congelador para que ceda apenas.","Licúa el açaí con la banana congelada y la miel hasta lograr una crema espesa.","Sirve de inmediato en bowls fríos.","Cubre con granola, fruta fresca y coco rallado.","Cómelo con cuchara antes de que se derrita."],ilu:{t:"bowl",c:["#6E4585","#EFC94C","#D98A8A"]}},
{id:"cl-01",pais:"Chile",nombre:"Pastel de choclo",desc:"Pino de carne, pollo, huevo y aceitunas bajo una capa dorada de choclo con albahaca, horneado en greda.",tiempo:100,porciones:6,dificultad:"Media",ingredientes:["8 choclos (o 1 kg de granos)","Hojas de albahaca","1/2 taza de leche","500 g de carne molida o picada","2 cebollas picadas","1 cdita de comino y 1 de ají de color","2 presas de pollo cocidas","3 huevos duros","12 aceitunas negras","Pasas y azúcar para espolvorear"],pasos:["Prepara el pino: sofríe la cebolla, agrega la carne, comino, ají de color y sal; cocina 15 minutos.","Muele el choclo con albahaca, cocínalo con leche y una pizca de sal revolviendo hasta espesar.","En fuentes de greda pon el pino, trozos de pollo, huevo duro, aceitunas y pasas.","Cubre con la pasta de choclo y espolvorea azúcar por encima.","Hornea a 200 °C por 30 minutos hasta que la superficie dore y burbujee.","Sirve bien caliente en la misma fuente."],ilu:{t:"pastel",c:["#EFC94C","#B5482F","#C98B2D"]}},
{id:"cl-02",pais:"Chile",nombre:"Empanadas de pino",desc:"Empanadas horneadas de masa suave rellenas de pino de carne, cebolla, huevo, aceituna y pasas.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["500 g de harina","100 g de manteca o margarina derretida","Salmuera tibia (agua, sal)","500 g de carne molida o picada","3 cebollas picadas","1 cdita de comino","1 cda de ají de color","2 huevos duros","12 aceitunas negras","Pasas y 1 huevo para pintar"],pasos:["Haz el pino el día anterior: sofríe cebolla, agrega carne y aliños, cocina y deja reposar para que jugoso.","Prepara la masa con harina, manteca y salmuera tibia; amasa hasta que quede lisa.","Estira discos, rellena con pino, un trozo de huevo, aceituna y pasas.","Cierra en forma rectangular doblando las puntas, el sello clásico chileno.","Pinta con huevo y hornea a 220 °C por 20–25 minutos hasta dorar."],ilu:{t:"empanada",c:["#E3B23C","#C98B2D","#3A2E2A"]}},
{id:"cl-03",pais:"Chile",nombre:"Cazuela de vacuno",desc:"Caldo reconfortante con carne, papa, zapallo, choclo y porotos verdes, servido humeante.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["6 trozos de osobuco o tapapecho","6 papas peladas","6 trozos de zapallo","2 choclos en rodajas","1 taza de porotos verdes","1/2 taza de arroz","1 cebolla","1 zanahoria","Orégano, comino y sal","Cilantro picado"],pasos:["Dora la carne en la olla y agrega cebolla y zanahoria picadas.","Cubre con agua caliente y cocina 50 minutos a fuego medio espumando el caldo.","Agrega papas, zapallo y choclo; cocina 15 minutos.","Suma el arroz y los porotos verdes y cocina 15 minutos más.","Rectifica los aliños y sirve cada plato con un trozo de cada ingrediente y cilantro fresco."],ilu:{t:"bowl",c:["#E3A23B","#EFC94C","#5C8A4E"]}},
{id:"cl-04",pais:"Chile",nombre:"Porotos granados",desc:"Porotos frescos cocidos con mazamorra de choclo, zapallo y albahaca: el sabor del verano chileno.",tiempo:75,porciones:6,dificultad:"Media",ingredientes:["1 kg de porotos granados desgranados","500 g de zapallo en cubos","4 choclos rallados o molidos","1 cebolla picada","2 dientes de ajo","1 cda de ají de color","Hojas de albahaca","Sal y pimienta","Pebre o ensalada chilena para acompañar"],pasos:["Cuece los porotos con el zapallo en agua hasta que estén tiernos (40 minutos).","Sofríe cebolla y ajo con ají de color y agrégalos a la olla.","Incorpora el choclo molido con albahaca y cocina 15 minutos revolviendo: la mazamorra espesa el guiso.","Aplasta parte del zapallo para dar cremosidad y rectifica la sal.","Sirve caliente con pebre o ensalada a la chilena."],ilu:{t:"bowl",c:["#D9C28A","#EFC94C","#5C8A4E"]}},
{id:"cl-05",pais:"Chile",nombre:"Charquicán",desc:"Guiso casero de papas y zapallo machacados con carne y verduras, coronado con huevo frito.",tiempo:60,porciones:4,dificultad:"Fácil",ingredientes:["400 g de posta molida o charqui desmenuzado","4 papas en cubos","400 g de zapallo en cubos","1 taza de porotos verdes picados","1 choclo desgranado","1 cebolla picada","1 cdita de comino y ají de color","4 huevos","Sal y pimienta"],pasos:["Sofríe la cebolla con los aliños y dora la carne.","Agrega papas y zapallo, cubre apenas con agua y cocina 20 minutos.","Suma porotos verdes y choclo, y cocina hasta que todo esté tierno.","Machaca groseramente con cuchara de palo: debe quedar cremoso pero con trozos.","Sirve con un huevo frito encima de cada plato."],ilu:{t:"plato",c:["#E0A53B","#5C8A4E","#EFC94C"]}},
{id:"cl-06",pais:"Chile",nombre:"Completo italiano",desc:"La versión chilena del hot dog: vienesa con tomate, palta y mayonesa, los colores de Italia.",tiempo:25,porciones:4,dificultad:"Fácil",ingredientes:["4 panes de completo","4 vienesas","2 tomates en cubitos","2 paltas maduras molidas","Mayonesa abundante","Sal"],pasos:["Calienta las vienesas en agua caliente sin hervir para que no revienten.","Entibia los panes al vapor o en horno suave.","Muele la palta con una pizca de sal.","Arma: vienesa, tomate, palta y un cordón generoso de mayonesa.","Sirve de inmediato, con servilletas a mano."],ilu:{t:"sandwich",c:["#E8C36A","#9DBE6E","#C0392B"]}},
{id:"cl-07",pais:"Chile",nombre:"Sopaipillas",desc:"Discos fritos de masa con zapallo, perfectos para la lluvia, con pebre o pasadas en chancaca.",tiempo:45,porciones:6,dificultad:"Fácil",ingredientes:["500 g de harina","250 g de zapallo camote cocido y molido","60 g de manteca derretida","1 cdita de sal","Aceite para freír","Para pasarlas: 1 pan de chancaca, cáscara de naranja y canela (opcional)"],pasos:["Mezcla la harina con el zapallo molido, la manteca y la sal hasta formar una masa suave.","Estira de 5 mm, corta discos y pínchalos con un tenedor.","Fríe en aceite caliente hasta que se inflen y doren por ambos lados.","Para la versión dulce, hierve la chancaca con naranja y canela y baña las sopaipillas.","Sírvelas calientes con pebre si las prefieres saladas."],ilu:{t:"pan",c:["#E0A53B","#C98B2D","#F2E3C2"]}},
{id:"cl-08",pais:"Chile",nombre:"Chorrillana",desc:"Papas fritas cubiertas de carne salteada, cebolla dorada y huevos: nacida en Valparaíso para compartir.",tiempo:50,porciones:4,dificultad:"Media",ingredientes:["1 kg de papas en bastones","500 g de lomo o posta en tiras","2 cebollas en pluma","4 huevos","2 vienesas o longaniza en rodajas (opcional)","Aceite para freír","Sal, pimienta y comino"],pasos:["Fríe las papas hasta dorar y mantenlas calientes en la fuente.","Saltea la carne a fuego fuerte con sal, pimienta y comino.","Dora la cebolla en la misma sartén hasta que caramelice.","Agrega los huevos revueltos a la sartén y mezcla apenas con carne y cebolla.","Vuelca todo sobre las papas y lleva la fuente al centro de la mesa."],ilu:{t:"plato",c:["#E8C36A","#8C4A32","#EFC94C"]}},
{id:"cl-09",pais:"Chile",nombre:"Pulmay (curanto en olla)",desc:"Mariscos, carnes y papas cocidos al vapor en capas, la versión casera del curanto chilote.",tiempo:120,porciones:8,dificultad:"Alta",ingredientes:["1 kg de choritos","1 kg de almejas","4 longanizas","4 presas de pollo","500 g de costillar de cerdo ahumado","8 papas","2 cebollas en cuartos","1 taza de vino blanco","Hojas de repollo","Ají de color y orégano"],pasos:["En una olla grande pon una cama de cebolla y las carnes sazonadas.","Agrega las papas y cubre con hojas de repollo.","Suma los mariscos bien lavados encima y vierte el vino blanco.","Tapa con más hojas de repollo y cocina a fuego medio 50–60 minutos sin destapar.","Sirve por capas con el caldito que se forma en pocillos aparte."],ilu:{t:"bowl",c:["#C9692B","#3A2E2A","#9DBE6E"]}},
{id:"cl-10",pais:"Chile",nombre:"Mote con huesillo",desc:"Refresco tradicional de duraznos deshidratados con mote de trigo, infaltable en verano.",tiempo:60,porciones:6,dificultad:"Fácil",ingredientes:["300 g de huesillos (duraznos secos) remojados desde la víspera","1 taza de azúcar o 1/2 pan de chancaca","1 rama de canela","2 tazas de mote de trigo cocido","Agua"],pasos:["Hierve los huesillos en su agua de remojo con azúcar y canela por 30 minutos.","Deja enfriar el jugo: debe quedar dulce y de color ámbar.","Refrigera hasta que esté bien helado.","Pon 2–3 cucharadas de mote en cada vaso.","Agrega un huesillo y completa con el jugo frío; se toma y se come con cuchara."],ilu:{t:"vaso",c:["#E0863B","#E8C36A","#C9692B"]}},
{id:"co-01",pais:"Colombia",nombre:"Bandeja paisa",desc:"El plato montañero por excelencia: frijoles, arroz, carnes, huevo, chicharrón, arepa y aguacate.",tiempo:120,porciones:4,dificultad:"Alta",ingredientes:["2 tazas de frijoles cargamanto (remojados)","2 tazas de arroz blanco cocido","400 g de carne molida","400 g de tocino para chicharrón","4 chorizos","4 huevos","2 plátanos maduros","4 arepas","1 aguacate","Hogao (tomate y cebolla larga sofritos)"],pasos:["Cocina los frijoles con un trozo de tocino hasta que estén tiernos y el caldo espese; termina con hogao.","Sofríe la carne molida con sal, comino y hogao.","Corta el tocino, cocínalo en agua y luego fríelo en su grasa hasta que truene: ese es el chicharrón.","Fríe los chorizos, las tajadas de maduro y los huevos.","Arma la bandeja: frijoles, arroz, carne, chicharrón, chorizo, huevo, tajadas, arepa y aguacate."],ilu:{t:"plato",c:["#8C4A32","#EFC94C","#9DBE6E"]}},
{id:"co-02",pais:"Colombia",nombre:"Ajiaco santafereño",desc:"Sopa bogotana de tres papas y pollo perfumada con guascas, servida con crema, alcaparras y mazorca.",tiempo:110,porciones:6,dificultad:"Media",ingredientes:["2 pechugas de pollo","500 g de papa criolla","500 g de papa pastusa","500 g de papa sabanera","3 mazorcas en trozos","1 manojo de guascas","2 dientes de ajo","1 cebolla larga","Crema de leche y alcaparras para servir","Aguacate"],pasos:["Cocina el pollo con cebolla, ajo y sal en 2,5 litros de agua; retira y desmenuza.","En el caldo cocina las papas pastusa y sabanera en rodajas hasta que empiecen a deshacerse.","Agrega la papa criolla y la mazorca; la criolla se disuelve y da el espesor típico.","Suma las guascas en los últimos 10 minutos.","Sirve con pollo desmenuzado, crema, alcaparras y aguacate aparte."],ilu:{t:"bowl",c:["#E8C36A","#EFC94C","#5C8A4E"]}},
{id:"co-03",pais:"Colombia",nombre:"Sancocho de gallina",desc:"Caldo sustancioso de gallina con yuca, plátano, papa y mazorca, plato de domingo y de río.",tiempo:150,porciones:8,dificultad:"Media",ingredientes:["1 gallina o pollo grande en presas","500 g de yuca en trozos","2 plátanos verdes en trozos","6 papas","3 mazorcas","1 cebolla larga","2 tomates","2 dientes de ajo","Cilantro y comino","Sal"],pasos:["Haz un guiso con cebolla, tomate y ajo, y dora las presas de gallina.","Cubre con 3 litros de agua y cocina 1 hora (la gallina pide tiempo).","Agrega plátano y yuca y cocina 25 minutos.","Suma papa y mazorca y cocina hasta que todo esté tierno.","Sazona con comino y sal, y termina con cilantro fresco; sirve con arroz y aguacate."],ilu:{t:"bowl",c:["#E3A23B","#EFC94C","#5C8A4E"]}},
{id:"co-04",pais:"Colombia",nombre:"Arepas de queso",desc:"Arepas de maíz rellenas y cubiertas de queso, doradas en budare o sartén.",tiempo:35,porciones:4,dificultad:"Fácil",ingredientes:["2 tazas de harina de maíz precocida","2,5 tazas de agua tibia","1,5 tazas de queso costeño o campesino rallado","2 cdas de mantequilla","1 cdita de sal"],pasos:["Mezcla la harina con agua, sal, mantequilla y la mitad del queso; amasa hasta que quede suave.","Deja reposar 5 minutos para que hidrate.","Forma bolas, rellena con el queso restante y aplana en discos de 1 cm.","Asa en sartén o budare a fuego medio 5–7 minutos por lado hasta dorar.","Sirve calientes con mantequilla por encima."],ilu:{t:"arepa",c:["#F2E3C2","#FFF6E3","#E8C36A"]}},
{id:"co-05",pais:"Colombia",nombre:"Tamales tolimenses",desc:"Masa de maíz y arroz con pollo, cerdo y verduras, envuelta en hoja de plátano y cocida por horas.",tiempo:240,porciones:10,dificultad:"Alta",ingredientes:["3 tazas de masa de maíz peto cocido y molido","1 taza de arroz semicocido","500 g de costilla de cerdo","500 g de pollo en presas","1 taza de arvejas","2 zanahorias en rodajas","4 huevos duros","Hogao abundante","Hojas de plátano soasadas","Comino, achiote y sal"],pasos:["Adoba las carnes desde la víspera con hogao, comino y achiote.","Mezcla la masa de maíz con el arroz, arvejas y parte del hogao.","Sobre dos hojas de plátano pon una capa de masa, las carnes, zanahoria y huevo.","Cierra formando un atado firme y amarra con cabuya.","Cocina los tamales en agua hirviendo con sal durante 2,5 a 3 horas.","Sirve con chocolate caliente, como manda la tradición."],ilu:{t:"envuelto",c:["#5C7A3E","#EFC94C","#8C6A4A"]}},
{id:"co-06",pais:"Colombia",nombre:"Patacones con hogao",desc:"Plátano verde frito dos veces hasta quedar crocante, servido con hogao de tomate y cebolla.",tiempo:40,porciones:4,dificultad:"Fácil",ingredientes:["3 plátanos verdes","Aceite para freír","Sal","Para el hogao: 3 tomates maduros picados","4 tallos de cebolla larga picada","1 diente de ajo","Comino y sal"],pasos:["Corta los plátanos en trozos de 4 cm y fríelos 3 minutos sin dorar del todo.","Aplástalos con una pataconera o entre dos tablas.","Fríelos de nuevo en aceite bien caliente hasta que queden dorados y crocantes; sala al salir.","Para el hogao, sofríe cebolla, ajo y tomate a fuego bajo hasta formar una salsa.","Sirve los patacones calientes con el hogao por encima o aparte."],ilu:{t:"plato",c:["#E0A53B","#C0392B","#5C8A4E"]}},
{id:"co-07",pais:"Colombia",nombre:"Changua",desc:"Sopa bogotana de leche con huevo pochado, cilantro y pan calado: desayuno de tierra fría.",tiempo:20,porciones:2,dificultad:"Fácil",ingredientes:["2 tazas de leche","2 tazas de agua","2 huevos","2 tallos de cebolla larga picada","Cilantro fresco picado","2 panes tostados o calados","Sal"],pasos:["Hierve la leche con el agua, la cebolla larga y sal.","Baja el fuego y casca los huevos enteros dentro, sin revolver.","Cocina 3–4 minutos hasta que la clara cuaje y la yema quede blanda.","Sirve en tazones con abundante cilantro.","Agrega el pan para que se cale en el caldo."],ilu:{t:"bowl",c:["#F2EDE3","#EFC94C","#5C8A4E"]}},
{id:"co-08",pais:"Colombia",nombre:"Empanadas colombianas",desc:"Empanadas fritas de masa de maíz rellenas de papa y carne, acompañadas de ají picante.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["2 tazas de harina de maíz precocida amarilla","2,5 tazas de caldo o agua tibia","300 g de carne de res cocida y picada","3 papas cocidas y machacadas","Hogao","Comino y sal","Aceite para freír","Ají de cilantro: cilantro, cebolla, limón, agua y picante"],pasos:["Prepara el relleno mezclando carne, papa machacada y hogao; sazona con comino.","Forma la masa con la harina, el caldo y sal; debe quedar moldeable.","Toma bolitas, aplánalas sobre plástico, rellena y dobla cerrando en media luna.","Fríe en aceite bien caliente hasta que queden doradas y crujientes.","Sírvelas con ají de cilantro y limón."],ilu:{t:"empanada",c:["#EFC94C","#E0A53B","#8C4A32"]}},
{id:"co-09",pais:"Colombia",nombre:"Arroz con coco",desc:"Arroz caribeño cocido en leche de coco con titoté caramelizado y pasas, dulce y salado.",tiempo:60,porciones:6,dificultad:"Media",ingredientes:["2 tazas de arroz","4 tazas de leche de coco (primera y segunda extracción)","3 cdas de azúcar o panela rallada","1/2 taza de uvas pasas","Sal"],pasos:["Hierve la primera leche de coco (la más espesa) hasta que el agua se evapore y la grasa se dore: ese es el titoté.","Agrega el azúcar y deja caramelizar apenas.","Suma el arroz, las pasas, la segunda leche de coco y sal.","Cocina destapado hasta que seque, luego tapa y baja el fuego 20 minutos.","Sirve como acompañamiento clásico de pescado frito con patacones."],ilu:{t:"plato",c:["#C9A36A","#8C6A4A","#5A3A2A"]}},
{id:"co-10",pais:"Colombia",nombre:"Buñuelos colombianos",desc:"Bolas doradas de queso costeño y almidón, infaltables en diciembre junto a la natilla.",tiempo:45,porciones:6,dificultad:"Media",ingredientes:["2 tazas de queso costeño rallado","1 taza de almidón de yuca","1/4 taza de fécula de maíz","1 huevo","2 cdas de azúcar","1 cdita de polvo de hornear","Leche si la masa lo pide","Aceite abundante para freír"],pasos:["Mezcla el queso con los almidones, el azúcar y el polvo de hornear.","Agrega el huevo y amasa; si está seca, suma leche por cucharadas.","Forma bolas medianas bien lisas.","Fríe en aceite a fuego medio-bajo: deben girar solas y dorarse parejo sin abrirse.","Escurre sobre papel y sírvelos tibios."],ilu:{t:"pan",c:["#E0A53B","#E8C36A","#C98B2D"]}},
{id:"ec-01",pais:"Ecuador",nombre:"Encebollado",desc:"Sopa costeña de pescado y yuca con cebolla encurtida, célebre por levantar el ánimo.",tiempo:75,porciones:4,dificultad:"Media",ingredientes:["500 g de albacora o atún fresco","500 g de yuca pelada","2 tomates","1 cebolla colorada en pluma fina","Jugo de 2 limones","Cilantro","1 cdita de comino","2 cdas de achiote en aceite","Chifles o canguil para acompañar","Sal y pimienta"],pasos:["Haz un refrito con tomate, parte de la cebolla, achiote y comino, y cubre con 2 litros de agua.","Cocina el pescado en ese caldo 10 minutos; retíralo y desmenúzalo en trozos grandes.","Cocina la yuca en el mismo caldo hasta que esté suave y córtala en trozos.","Encurte la cebolla restante con limón y sal.","Sirve caldo, yuca y pescado en cada plato, corona con cebolla encurtida y cilantro.","Acompaña con chifles, canguil y más limón."],ilu:{t:"bowl",c:["#E3A23B","#F2E3C2","#B05A8C"]}},
{id:"ec-02",pais:"Ecuador",nombre:"Ceviche de camarón",desc:"Camarones en jugo de limón, naranja y tomate con cebolla y cilantro, al estilo ecuatoriano.",tiempo:40,porciones:4,dificultad:"Fácil",ingredientes:["500 g de camarones limpios","Jugo de 4 limones","Jugo de 1 naranja","1/2 taza de salsa de tomate","1 cebolla colorada en pluma encurtida","2 tomates picados","Cilantro picado","1 cda de aceite","Sal y pimienta","Chifles y canguil para servir"],pasos:["Hierve los camarones 2 minutos en agua con sal y enfríalos de inmediato; reserva un poco del agua de cocción.","Mezcla los jugos de limón y naranja con la salsa de tomate y un poco del caldo de camarón.","Agrega camarones, cebolla encurtida, tomate y cilantro.","Sazona con sal, pimienta y el chorrito de aceite; refrigera 20 minutos.","Sirve frío con chifles, canguil y arroz si quieres el combo completo."],ilu:{t:"bowl",c:["#D98A8A","#E0863B","#5C8A4E"]}},
{id:"ec-03",pais:"Ecuador",nombre:"Locro de papa",desc:"Sopa cremosa de papa con queso y aguacate, clásico de la sierra ecuatoriana.",tiempo:50,porciones:4,dificultad:"Fácil",ingredientes:["1 kg de papas (mitad en cubos, mitad para deshacer)","1 cebolla blanca picada","2 dientes de ajo","1 cdita de achiote en aceite","1 taza de leche","150 g de queso fresco desmenuzado","1 aguacate","Cilantro","Sal y comino"],pasos:["Sofríe cebolla y ajo con el achiote.","Agrega las papas, cubre con agua y cocina hasta que parte de ellas se deshaga y espese la sopa.","Vierte la leche y cocina 5 minutos más sin que hierva fuerte.","Apaga el fuego e incorpora el queso desmenuzado.","Sirve con aguacate en láminas y cilantro; el ají criollo es bienvenido."],ilu:{t:"bowl",c:["#EFD27A","#F2E3C2","#9DBE6E"]}},
{id:"ec-04",pais:"Ecuador",nombre:"Llapingachos",desc:"Tortillas de papa rellenas de queso, doradas en plancha y servidas con salsa de maní.",tiempo:60,porciones:4,dificultad:"Media",ingredientes:["1 kg de papas cocidas","1 cebolla blanca picada fina","2 cdas de achiote en aceite","1 taza de queso fresco desmenuzado","Para la salsa: 1/2 taza de maní tostado licuado con 1 taza de leche","Chorizo, huevo frito y curtido para acompañar","Sal"],pasos:["Aplasta las papas calientes y mézclalas con la cebolla sofrita en achiote y sal.","Deja reposar la masa 30 minutos en frío.","Forma tortillas gruesas rellenas con queso en el centro.","Dóralas en plancha o sartén con poco aceite hasta formar costra por ambos lados.","Cocina el maní licuado con leche y cebolla hasta espesar.","Sirve los llapingachos bañados en salsa de maní con sus acompañamientos."],ilu:{t:"arepa",c:["#E0A53B","#F2E3C2","#C98B2D"]}},
{id:"ec-05",pais:"Ecuador",nombre:"Fanesca",desc:"Sopa ceremonial de Semana Santa con doce granos, zapallo y bacalao en leche.",tiempo:180,porciones:10,dificultad:"Alta",ingredientes:["250 g de bacalao seco (remojado desde la víspera)","1 taza de cada grano: habas, chochos, arvejas, fréjol, maíz tierno, lenteja (y los que sumes hasta doce)","500 g de zapallo y sambo cocidos","2 tazas de leche","1/2 taza de maní licuado con leche","Refrito de cebolla, ajo, comino y achiote","Queso fresco","Empanaditas, maduro frito y huevo duro para decorar"],pasos:["Cocina cada grano por separado hasta que esté tierno (el secreto de la textura).","Haz el refrito y agrega el zapallo y sambo hechos puré con leche.","Incorpora el maní licuado y los granos; cocina a fuego bajo revolviendo.","Cocina el bacalao en leche 10 minutos y agrégalo con su leche a la olla.","Ajusta sal y espesor: debe quedar cremosa y abundante.","Sirve decorada con huevo duro, queso, maduro frito y empanaditas."],ilu:{t:"bowl",c:["#E0C26A","#9DBE6E","#EFC94C"]}},
{id:"ec-06",pais:"Ecuador",nombre:"Bolón de verde",desc:"Bola de plátano verde majado con chicharrón o queso, desayuno de campeones costeños.",tiempo:35,porciones:4,dificultad:"Fácil",ingredientes:["4 plátanos verdes","150 g de chicharrón en trozos o queso rallado","2 cdas de mantequilla o aceite con achiote","Sal","Café o jugo para acompañar (huevo frito opcional)"],pasos:["Pela los verdes, córtalos en trozos y fríelos o cocínalos hasta que estén suaves.","Májalos calientes en mortero o tabla hasta formar una masa.","Mezcla con mantequilla, sal y el chicharrón o queso.","Forma bolas compactas con las manos.","Dóralas brevemente en sartén y sírvelas calientes, con huevo frito si el hambre aprieta."],ilu:{t:"pan",c:["#9DA84E","#7A8C3B","#C98B2D"]}},
{id:"ec-07",pais:"Ecuador",nombre:"Seco de chivo",desc:"Estofado de chivo en salsa de naranjilla y cerveza, servido con arroz amarillo y maduro.",tiempo:130,porciones:6,dificultad:"Media",ingredientes:["1,5 kg de carne de chivo o borrego en trozos","1 taza de jugo de naranjilla","1 taza de cerveza o chicha","2 cebollas","2 tomates","1 pimiento","4 dientes de ajo","1 cda de achiote","Cilantro y comino","Arroz amarillo y plátano maduro frito para servir"],pasos:["Licúa cebolla, tomate, pimiento y ajo con la naranjilla y la cerveza.","Sella la carne en una olla con achiote.","Vierte la salsa licuada, sazona con comino y sal, y cocina tapado a fuego bajo 1,5 horas.","Revisa que la carne esté muy suave y la salsa espesa.","Termina con cilantro y sirve con arroz amarillo y maduro frito."],ilu:{t:"plato",c:["#8C5A32","#EFC94C","#5C8A4E"]}},
{id:"ec-08",pais:"Ecuador",nombre:"Encocado de pescado",desc:"Pescado esmeraldeño cocido en salsa de coco con hierbas de monte, puro sabor del Pacífico.",tiempo:50,porciones:4,dificultad:"Media",ingredientes:["800 g de pescado fresco en trozos","Jugo de 1 limón","400 ml de leche de coco","1 cebolla picada","1 pimiento picado","2 tomates picados","2 dientes de ajo","Chillangua o cilantro","1 cdita de achiote","Arroz y patacones para servir"],pasos:["Adoba el pescado con limón, ajo y sal por 20 minutos.","Haz un refrito con cebolla, pimiento, tomate y achiote.","Agrega la leche de coco y cocina 10 minutos a fuego bajo.","Incorpora el pescado y cocina 10–12 minutos sin revolver bruscamente.","Perfuma con chillangua y sirve con arroz blanco y patacones."],ilu:{t:"pescado",c:["#E0A53B","#C9692B","#5C8A4E"]}},
{id:"ec-09",pais:"Ecuador",nombre:"Fritada",desc:"Cerdo cocido en su propio jugo y dorado en paila de bronce, con mote, maduro y curtido.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["1,5 kg de carne de cerdo en trozos","1 cabeza de ajo machacada","1 cebolla blanca en trozos","1 cda de comino","2 tazas de agua o cerveza","2 tazas de mote cocido","2 plátanos maduros fritos","Curtido de cebolla y tomate","Papas cocidas (opcional)","Sal"],pasos:["Pon el cerdo en una paila con agua, ajo, cebolla, comino y sal.","Cocina a fuego medio hasta que el agua se evapore.","Sigue cocinando: la carne se dora en su propia grasa, girando los trozos.","Retira cuando esté dorada por fuera y jugosa por dentro.","Sirve con mote, maduro frito, papas y curtido fresco."],ilu:{t:"plato",c:["#B5713A","#F2E3C2","#C0392B"]}},
{id:"ec-10",pais:"Ecuador",nombre:"Empanadas de viento",desc:"Empanadas fritas de queso que se inflan como globos y se espolvorean con azúcar.",tiempo:45,porciones:6,dificultad:"Fácil",ingredientes:["3 tazas de harina","100 g de mantequilla fría","1 huevo","Agua tibia con sal","2 tazas de queso fresco rallado","1/2 cebolla blanca picada fina (opcional)","Aceite abundante para freír","Azúcar para espolvorear"],pasos:["Forma una masa suave con harina, mantequilla, huevo y agua; deja reposar 30 minutos.","Mezcla el queso con la cebolla picada.","Estira discos delgados, rellena y cierra con repulgue torcido.","Fríe en abundante aceite caliente bañando la superficie para que se inflen.","Escurre y espolvorea azúcar antes de servir, todavía calientes."],ilu:{t:"empanada",c:["#E8C36A","#D9A05B","#FFF6E3"]}},
{id:"py-01",pais:"Paraguay",nombre:"Sopa paraguaya",desc:"La única sopa sólida del mundo: torta esponjosa de harina de maíz, queso y cebolla.",tiempo:70,porciones:8,dificultad:"Fácil",ingredientes:["3 tazas de harina de maíz","300 g de queso Paraguay o fresco en trozos","2 cebollas picadas","100 g de grasa de cerdo o mantequilla","4 huevos","2 tazas de leche","Sal gruesa"],pasos:["Hierve la cebolla picada con un poco de agua y sal hasta que esté transparente; escurre.","Bate la grasa con los huevos y agrega el queso desmenuzado.","Incorpora la cebolla, la harina de maíz y la leche alternando hasta lograr una mezcla cremosa.","Vierte en una fuente engrasada de unos 4 cm de alto.","Hornea a 200 °C por 40–45 minutos hasta dorar; corta en cuadrados y sirve tibia."],ilu:{t:"pastel",c:["#EFC94C","#C98B2D","#E8C36A"]}},
{id:"py-02",pais:"Paraguay",nombre:"Chipa",desc:"Roscas de almidón de mandioca con queso y anís, el aroma de toda Semana Santa paraguaya.",tiempo:60,porciones:6,dificultad:"Media",ingredientes:["500 g de almidón de mandioca","250 g de queso Paraguay o semiduro rallado","100 g de grasa de cerdo o mantequilla","3 huevos","1/2 taza de leche","1 cdita de anís en grano","1 cdita de sal"],pasos:["Bate la grasa con los huevos hasta integrar.","Agrega el queso, la sal y el anís.","Incorpora el almidón alternando con la leche hasta formar una masa lisa que no se pegue.","Forma roscas o palitos.","Hornea a 220 °C por 15–20 minutos: doradas por fuera, húmedas por dentro.","Cómelas tibias, como manda el chiperío."],ilu:{t:"pan",c:["#E8C36A","#FFF6E3","#C98B2D"]}},
{id:"py-03",pais:"Paraguay",nombre:"Chipa guazú",desc:"Pastel húmedo de choclo fresco molido con queso y cebolla, primo veraniego de la sopa paraguaya.",tiempo:75,porciones:8,dificultad:"Fácil",ingredientes:["8 choclos frescos desgranados","300 g de queso Paraguay o fresco","2 cebollas picadas","100 g de grasa o mantequilla","4 huevos","1 taza de leche","Sal"],pasos:["Muele o procesa los granos de choclo dejando algo de textura.","Sofríe la cebolla en la grasa hasta transparentar.","Mezcla el choclo con huevos, leche, queso en trozos, cebolla y sal.","Vierte en fuente engrasada.","Hornea a 200 °C por 45 minutos hasta que cuaje y dore; sirve como plato o acompañamiento."],ilu:{t:"pastel",c:["#EFD27A","#C98B2D","#EFC94C"]}},
{id:"py-04",pais:"Paraguay",nombre:"Mbeyú",desc:"Torta plana de almidón de mandioca y queso hecha en sartén, crocante y sin gluten.",tiempo:25,porciones:4,dificultad:"Fácil",ingredientes:["2 tazas de almidón de mandioca","200 g de queso Paraguay desmenuzado","3 cdas de grasa de cerdo o mantequilla","1/2 taza de leche (aproximado)","Sal"],pasos:["Mezcla el almidón con la grasa frotando con los dedos hasta formar un arenado.","Agrega el queso y la sal, y humedece apenas con leche: debe quedar granulado, no masa.","Calienta una sartén y esparce una capa del granulado presionando con espátula.","Cocina a fuego medio hasta que tome cuerpo y dore; da vuelta como panqueque.","Sirve caliente, ideal con cocido o café con leche."],ilu:{t:"arepa",c:["#F2E3C2","#FFF6E3","#E8C36A"]}},
{id:"py-05",pais:"Paraguay",nombre:"Vorí vorí",desc:"Caldo dorado de gallina con bolitas de harina de maíz y queso flotando como soles.",tiempo:80,porciones:6,dificultad:"Media",ingredientes:["1 gallina o pollo en presas","1 cebolla picada","1 tomate picado","1 pimiento (locote) picado","1 cdita de cúrcuma o azafrán del país","1,5 tazas de harina de maíz","100 g de queso Paraguay rallado","2 cdas de grasa","Orégano y sal"],pasos:["Dora las presas con cebolla, tomate y locote, agrega la cúrcuma y cubre con agua.","Cocina 40 minutos hasta tener un caldo sabroso.","Para los vorí: mezcla la harina de maíz con queso, un poco de grasa y caldo caliente hasta poder formar bolitas.","Forma bolitas de 2–3 cm y échalas al caldo hirviendo.","Cocina 10 minutos hasta que floten y estén firmes; sirve bien caliente con orégano."],ilu:{t:"bowl",c:["#E3B23C","#EFD27A","#5C8A4E"]}},
{id:"py-06",pais:"Paraguay",nombre:"So'o yosopy",desc:"Sopa de carne molida fresca con arroz, sencilla y reparadora, de nombre guaraní.",tiempo:50,porciones:4,dificultad:"Fácil",ingredientes:["500 g de carne de res molida muy fresca","1 cebolla picada fina","1 locote (pimiento) picado","2 tomates picados","1/2 taza de arroz o fideos finos","2 cdas de aceite","2 litros de agua","Sal (al final) y orégano","Mandioca cocida para acompañar"],pasos:["Sofríe cebolla, locote y tomate en el aceite.","Agrega la carne molida y revuelve deshaciéndola para que no forme grumos.","Vierte el agua fría y cocina 20 minutos a fuego medio.","Suma el arroz y cocina hasta que esté a punto.","Sala recién al final (la tradición dice que si no, se corta) y sirve con mandioca."],ilu:{t:"bowl",c:["#C96A4A","#E3A23B","#5C8A4E"]}},
{id:"py-07",pais:"Paraguay",nombre:"Pira caldo",desc:"Sopa de pescado de río con tomate, locote y un toque de leche, sabor del Paraguay fluvial.",tiempo:60,porciones:4,dificultad:"Media",ingredientes:["1 kg de pescado de río (surubí o tararira) en postas","2 cebollas picadas","2 tomates picados","1 locote picado","2 cdas de grasa o aceite","1 taza de leche","100 g de queso Paraguay (opcional)","Comino, laurel y sal","Mandioca cocida"],pasos:["Sofríe cebolla, tomate y locote en la grasa hasta formar una salsa.","Agrega agua caliente, laurel y comino, y deja hervir 10 minutos.","Incorpora las postas de pescado y cocina 15 minutos a fuego suave.","Vierte la leche (y el queso si usas) y calienta sin hervir fuerte.","Sirve caliente con mandioca; cuidado con las espinas y con repetir."],ilu:{t:"bowl",c:["#E0A53B","#F2E3C2","#C0392B"]}},
{id:"py-08",pais:"Paraguay",nombre:"Pastel mandi'o",desc:"Empanada frita de masa de mandioca rellena de so'o ku'i (carne picada), dorada y crocante.",tiempo:90,porciones:6,dificultad:"Media",ingredientes:["1 kg de mandioca cocida y molida","1 taza de almidón de mandioca","1 huevo","500 g de carne picada a cuchillo","1 cebolla picada","1 locote picado","Comino, orégano y sal","Aceite o grasa para freír"],pasos:["Prepara el so'o ku'i: sofríe cebolla y locote, agrega la carne y los aliños, y cocina hasta secar.","Amasa la mandioca molida con el almidón, el huevo y sal hasta lograr una masa lisa.","Toma porciones, aplana en discos, rellena y cierra como empanada.","Fríe en grasa o aceite caliente hasta dorar por ambos lados.","Escurre y sirve caliente, con limón si te gusta."],ilu:{t:"empanada",c:["#E0B45B","#C98B2D","#8C4A32"]}},
{id:"py-09",pais:"Paraguay",nombre:"Kiveve",desc:"Crema agridulce de calabaza andai con harina de maíz y queso, entre plato y postre.",tiempo:45,porciones:4,dificultad:"Fácil",ingredientes:["1 kg de calabaza andai (zapallo) en trozos","1/2 taza de harina de maíz","150 g de queso Paraguay en trozos","2 cdas de grasa o mantequilla","2 cdas de azúcar","1 taza de leche","Sal"],pasos:["Cocina la calabaza en poca agua hasta que esté muy tierna y hazla puré con su caldo.","Vuelve al fuego con la grasa, el azúcar y una pizca de sal.","Agrega la harina de maíz en lluvia, revolviendo para que no grumee.","Cocina 10 minutos sumando leche hasta lograr una crema.","Apaga e incorpora el queso; sirve tibio como desayuno, guarnición o merienda."],ilu:{t:"bowl",c:["#E0863B","#EFC94C","#F2E3C2"]}},
{id:"py-10",pais:"Paraguay",nombre:"Tereré",desc:"La bebida nacional: yerba mate con agua helada y hierbas refrescantes, compartida en ronda.",tiempo:10,porciones:2,dificultad:"Fácil",ingredientes:["Yerba mate (de corte grueso, ideal para tereré)","1 litro de agua bien helada con hielo","Hierbas refrescantes (menta'i, cedrón, cola de caballo) machacadas","Guampa y bombilla","Rodajas de limón (opcional)"],pasos:["Machaca las hierbas en un mortero y agrégalas a la jarra de agua helada.","Llena dos tercios de la guampa con yerba.","Inclina la guampa, inserta la bombilla y moja la yerba con un primer chorro.","Ceba sirviendo agua helada y pasa la guampa: el orden de la ronda es sagrado.","Repón agua y hielo, y conversa: el tereré no se apura."],ilu:{t:"vaso",c:["#7A8C3B","#9DBE6E","#EFC94C"]}},
{id:"pe-01",pais:"Perú",nombre:"Ceviche peruano",desc:"Pescado fresco marinado en leche de tigre con ají limo, cebolla y cilantro, servido con camote y choclo.",tiempo:30,porciones:4,dificultad:"Media",ingredientes:["800 g de pescado blanco muy fresco en cubos","Jugo de 10 limones","1 cebolla roja en pluma fina","1 ají limo picado fino","1 diente de ajo molido","Cilantro picado","1 trozo de jengibre (opcional)","2 camotes cocidos","2 choclos cocidos","Sal y pimienta"],pasos:["Enjuaga la cebolla en agua fría para suavizarla.","Sazona el pescado con sal, pimienta y ajo.","Agrega el jugo de limón y el ají limo, y mezcla suavemente: la marinación toma minutos, no horas.","Incorpora la cebolla y el cilantro.","Sirve de inmediato con camote, choclo y la leche de tigre que quedó en el bowl."],ilu:{t:"plato",c:["#F2EDE3","#D98A8A","#E0863B"]}},
{id:"pe-02",pais:"Perú",nombre:"Lomo saltado",desc:"Tiras de lomo salteadas al wok con cebolla, tomate y sillao, servidas con papas fritas y arroz.",tiempo:35,porciones:4,dificultad:"Media",ingredientes:["600 g de lomo de res en tiras","2 cebollas rojas en gajos gruesos","3 tomates en gajos","1 ají amarillo en tiras","3 cdas de sillao (salsa de soya)","2 cdas de vinagre tinto","2 dientes de ajo","Cilantro","400 g de papas fritas","Arroz blanco cocido"],pasos:["Sella la carne en tandas en sartén o wok muy caliente y reserva.","Saltea ajo, cebolla y ají amarillo 1 minuto a fuego máximo.","Vuelve la carne, agrega el tomate, el sillao y el vinagre; flambea si te animas.","Saltea 2 minutos más: el tomate debe quedar entero y jugoso.","Mezcla con las papas fritas, corona con cilantro y sirve con arroz."],ilu:{t:"plato",c:["#8C4A32","#C0392B","#E8C36A"]}},
{id:"pe-03",pais:"Perú",nombre:"Ají de gallina",desc:"Pollo deshilachado en crema de ají amarillo, pan y pecanas, sobre papas con arroz.",tiempo:60,porciones:4,dificultad:"Media",ingredientes:["2 pechugas de pollo","4 ajíes amarillos sin venas licuados","4 rebanadas de pan de molde remojadas en leche","1 cebolla picada","3 dientes de ajo","1/2 taza de pecanas o nueces (opcional)","1/4 taza de queso parmesano","4 papas cocidas","Huevo duro y aceitunas","Arroz blanco"],pasos:["Cuece el pollo, deshiláchalo y reserva el caldo.","Sofríe cebolla y ajo, agrega el ají amarillo licuado y cocina 5 minutos.","Suma el pan licuado con la leche y cocina removiendo hasta espesar.","Incorpora el pollo, las pecanas molidas, el parmesano y caldo hasta lograr cremosidad.","Sirve sobre rodajas de papa, con arroz, medio huevo duro y aceituna."],ilu:{t:"plato",c:["#E3B23C","#F2E3C2","#3A2E2A"]}},
{id:"pe-04",pais:"Perú",nombre:"Causa limeña",desc:"Capas de puré de papa amarilla con ají y limón, rellenas de pollo o atún con mayonesa.",tiempo:50,porciones:6,dificultad:"Media",ingredientes:["1 kg de papa amarilla cocida","3 cdas de pasta de ají amarillo","Jugo de 3 limones","4 cdas de aceite","1 pechuga de pollo cocida y deshilachada (o 2 latas de atún)","1/2 taza de mayonesa","1 palta en láminas","Huevo duro y aceitunas para decorar","Sal y pimienta"],pasos:["Prensa las papas aún tibias y deja enfriar.","Amasa el puré con ají amarillo, limón, aceite, sal y pimienta hasta que quede sedoso.","Mezcla el pollo o atún con la mayonesa.","En un molde alterna capas: puré, relleno, palta y de nuevo puré.","Refrigera 30 minutos, desmolda y decora con huevo y aceitunas."],ilu:{t:"pastel",c:["#EFD27A","#F2E3C2","#9DBE6E"]}},
{id:"pe-05",pais:"Perú",nombre:"Anticuchos",desc:"Brochetas de corazón de res marinadas en ají panca y asadas a la parrilla, estrella callejera limeña.",tiempo:60,porciones:4,dificultad:"Media",ingredientes:["1 kg de corazón de res limpio en cubos","4 cdas de pasta de ají panca","1/4 taza de vinagre tinto","4 dientes de ajo molidos","1 cdita de comino y orégano","Aceite y sal","Palitos de brocheta","Papas doradas y choclo para acompañar","Salsa de ají"],pasos:["Marina el corazón con ají panca, vinagre, ajo, comino, orégano y sal por al menos 2 horas.","Ensarta 3–4 trozos por palito.","Asa a fuego fuerte en parrilla o plancha, pintando con la marinada.","Cocina 2–3 minutos por lado: por fuera dorado, por dentro jugoso.","Sirve con papa dorada, choclo y ají al gusto."],ilu:{t:"brocheta",c:["#8C3A2A","#C0392B","#E8C36A"]}},
{id:"pe-06",pais:"Perú",nombre:"Papa a la huancaína",desc:"Papas bañadas en salsa cremosa de ají amarillo y queso fresco, entrada infaltable.",tiempo:30,porciones:4,dificultad:"Fácil",ingredientes:["6 papas cocidas en rodajas","4 ajíes amarillos sin venas","200 g de queso fresco","1/2 taza de leche evaporada","4 galletas de soda","2 cdas de aceite","Hojas de lechuga","Huevo duro y aceitunas negras","Sal"],pasos:["Saltea los ajíes con un poco de aceite para suavizar su picor.","Licúa los ajíes con queso, leche, galletas y sal hasta lograr una crema espesa.","Acomoda rodajas de papa sobre hojas de lechuga.","Baña con la salsa huancaína.","Decora con huevo duro y aceitunas; sirve fría o a temperatura ambiente."],ilu:{t:"plato",c:["#EFD27A","#F2E3C2","#3A2E2A"]}},
{id:"pe-07",pais:"Perú",nombre:"Rocoto relleno",desc:"Rocotos arequipeños rellenos de carne y gratinados con queso, acompañados de pastel de papa.",tiempo:80,porciones:4,dificultad:"Alta",ingredientes:["4 rocotos grandes","500 g de carne molida","1 cebolla picada","2 cdas de pasta de ají panca","1/4 taza de maní tostado picado","2 huevos duros picados","Pasas (opcional)","150 g de queso fresco o paria en láminas","Azúcar y vinagre para hervir los rocotos","Leche y huevo para el gratín"],pasos:["Desvena los rocotos y hiérvelos 3 veces en agua con azúcar y vinagre para domar el picante.","Sofríe cebolla con ají panca, agrega la carne y cocina; mezcla con maní, pasas y huevo duro.","Rellena los rocotos y cúbrelos con láminas de queso.","Colócalos en una fuente, baña con leche batida con huevo.","Hornea a 180 °C por 20 minutos hasta gratinar; sirve con pastel de papa."],ilu:{t:"plato",c:["#C0392B","#F2E3C2","#8C4A32"]}},
{id:"pe-08",pais:"Perú",nombre:"Arroz chaufa",desc:"Arroz frito al estilo chifa con pollo, tortilla de huevo, cebolla china y sillao.",tiempo:30,porciones:4,dificultad:"Fácil",ingredientes:["4 tazas de arroz cocido y frío","2 pechugas de pollo en cubos","3 huevos","1 atado de cebolla china picada","1 trozo de kion (jengibre) rallado","4 cdas de sillao","1 cdita de aceite de ajonjolí","1 pimiento rojo picado (opcional)","Aceite y sal"],pasos:["Haz una tortilla con los huevos, córtala en cuadritos y reserva.","Saltea el pollo a fuego fuerte hasta dorar.","Agrega kion, pimiento y la parte blanca de la cebolla china.","Suma el arroz frío y el sillao, salteando para que cada grano se impregne.","Termina con la tortilla, el aceite de ajonjolí y la cebolla china verde."],ilu:{t:"plato",c:["#C9A36A","#EFC94C","#5C8A4E"]}},
{id:"pe-09",pais:"Perú",nombre:"Suspiro a la limeña",desc:"Manjar blanco sedoso coronado con merengue al oporto: dulce, suave y limeñísimo.",tiempo:50,porciones:6,dificultad:"Media",ingredientes:["1 lata de leche evaporada","1 lata de leche condensada","5 yemas","1 cdita de esencia de vainilla","Para el merengue: 3 claras","1 taza de azúcar","1/2 taza de oporto","Canela molida para espolvorear"],pasos:["Cocina las dos leches a fuego bajo revolviendo hasta que tome punto de manjar (ver el fondo de la olla).","Fuera del fuego agrega las yemas batidas y la vainilla; cocina 2 minutos más sin hervir.","Reparte el manjar en copas y deja entibiar.","Haz un almíbar con azúcar y oporto a punto de hilo, y viértelo en hilo sobre las claras batidas hasta lograr un merengue firme.","Corona las copas con merengue y espolvorea canela."],ilu:{t:"copa",c:["#F2E3C2","#C98B5A","#E8D9F2"]}},
{id:"pe-10",pais:"Perú",nombre:"Pisco sour",desc:"El cóctel bandera del Perú: pisco, limón, jarabe y clara de huevo coronado con amargo de angostura.",tiempo:10,porciones:2,dificultad:"Fácil",ingredientes:["6 oz (180 ml) de pisco quebranta","2 oz de jugo de limón fresco","2 oz de jarabe de goma","1 clara de huevo","Hielo abundante","Gotas de amargo de angostura"],pasos:["Pon en la coctelera el pisco, el limón, el jarabe y la clara.","Agita en seco (sin hielo) 10 segundos para emulsionar la espuma.","Agrega hielo y agita con energía 15 segundos más.","Cuela en copas frías: la espuma debe coronar el cóctel.","Decora con 3 gotas de amargo de angostura sobre la espuma."],ilu:{t:"vaso",c:["#EFE3B5","#FFF6E3","#8C4A32"]}},
{id:"uy-01",pais:"Uruguay",nombre:"Chivito al pan",desc:"El sándwich nacional uruguayo: churrasco fino con jamón, muzzarella, huevo, tomate y mayonesa.",tiempo:35,porciones:2,dificultad:"Media",ingredientes:["2 churrascos finos de lomo o nalga","2 panes tipo pebete o brioche grandes","2 fetas de jamón cocido","2 fetas de muzzarella","2 fetas de panceta","2 huevos","Tomate y lechuga","Mayonesa","Papas fritas para acompañar","Sal y pimienta"],pasos:["Dora la panceta y fríe los huevos; reserva.","Cocina los churrascos a la plancha 1–2 minutos por lado y cúbrelos con jamón y muzzarella para que funda.","Tuesta el pan y unta mayonesa generosamente.","Arma: lechuga, tomate, churrasco con queso, panceta y huevo frito.","Cierra, presiona apenas y sirve con papas fritas."],ilu:{t:"sandwich",c:["#E8C36A","#8C4A32","#C0392B"]}},
{id:"uy-02",pais:"Uruguay",nombre:"Asado uruguayo",desc:"Tira de asado y achuras a las brasas de leña, con ensalada criolla y tiempo por delante.",tiempo:150,porciones:6,dificultad:"Media",ingredientes:["2 kg de tira de asado","1 kg de pulpón o vacío","Chorizos y morcillas","Sal gruesa","Leña o carbón de buena calidad","Ensalada criolla: tomate, cebolla, morrón, aceite y vinagre"],pasos:["Prende el fuego con leña y espera brasas firmes: en Uruguay el asado se hace con calma.","Sala la carne con sal gruesa.","Comienza con chorizos y morcillas para el picoteo.","Cocina la tira a fuego suave 70–90 minutos, hueso abajo primero.","Da vuelta, termina de dorar y sirve con ensalada criolla y pan."],ilu:{t:"plato",c:["#8C4A32","#C0392B","#5C8A4E"]}},
{id:"uy-03",pais:"Uruguay",nombre:"Pamplona de pollo",desc:"Pechuga rellena de jamón, queso y morrón, enrollada y asada a la parrilla.",tiempo:70,porciones:4,dificultad:"Media",ingredientes:["2 pechugas grandes abiertas en mariposa","4 fetas de jamón","4 fetas de queso muzzarella o dambo","1 morrón rojo asado en tiras","2 huevos duros (opcional)","Sal, pimienta y pimentón","Hilo de cocina o malla","Aceite"],pasos:["Aplana las pechugas abiertas y salpimienta.","Cubre con jamón, queso, tiras de morrón y huevo duro.","Enrolla bien apretado y ata con hilo o coloca en malla.","Cocina a la parrilla o al horno a fuego medio 40–50 minutos, girando.","Deja reposar 5 minutos, corta en rodajas y sirve con ensalada o papas."],ilu:{t:"plato",c:["#D9A05B","#C0392B","#F2E3C2"]}},
{id:"uy-04",pais:"Uruguay",nombre:"Buseca",desc:"Guiso invernal de mondongo con porotos, panceta y verduras, herencia italiana del Río de la Plata.",tiempo:150,porciones:6,dificultad:"Alta",ingredientes:["1 kg de mondongo limpio","250 g de porotos blancos (remojados)","150 g de panceta","2 chorizos","1 cebolla","1 zanahoria","1 morrón","2 tomates o 1 lata de tomate","1 cda de pimentón","Laurel, sal y pimienta"],pasos:["Hierve el mondongo en agua con laurel 1 hora; escurre y córtalo en tiras.","Sofríe panceta, cebolla, zanahoria y morrón en la olla.","Agrega el tomate, el pimentón, el mondongo y los porotos.","Cubre con caldo y cocina a fuego bajo 1 hora hasta que los porotos estén tiernos.","Suma el chorizo en rodajas en los últimos 20 minutos y sirve bien caliente."],ilu:{t:"bowl",c:["#C9762B","#F2E3C2","#C0392B"]}},
{id:"uy-05",pais:"Uruguay",nombre:"Puchero",desc:"Carnes y verduras hervidas lentamente: el caldo se toma de entrada y el resto es el plato principal.",tiempo:150,porciones:8,dificultad:"Media",ingredientes:["1 kg de falda o aguja","2 osobucos","1 trozo de panceta","2 chorizos","4 papas","2 batatas","4 zanahorias","2 choclos","1/2 zapallo en trozos","1 taza de garbanzos remojados y apio, puerro y repollo"],pasos:["Hierve las carnes con apio y puerro espumando el caldo durante 1 hora.","Agrega los garbanzos y cocina 30 minutos.","Suma las verduras por dureza: zanahoria primero, luego papa, batata, zapallo, choclo y repollo.","Cocina hasta que todo esté tierno y el caldo concentrado.","Sirve primero el caldo con fideos finos y luego una fuente con carnes y verduras."],ilu:{t:"bowl",c:["#E3A23B","#EFC94C","#9DBE6E"]}},
{id:"uy-06",pais:"Uruguay",nombre:"Fainá",desc:"Torta fina de harina de garbanzos al horno, compañera obligada de la pizza uruguaya.",tiempo:40,porciones:6,dificultad:"Fácil",ingredientes:["250 g de harina de garbanzos","750 ml de agua","1/2 taza de aceite de oliva","1 cdita de sal","Pimienta negra abundante"],pasos:["Mezcla la harina de garbanzos con el agua, la sal y la mitad del aceite; deja reposar 30 minutos.","Calienta el horno al máximo con una asadera con el resto del aceite adentro.","Vierte la mezcla en la asadera caliente: debe quedar de 1 cm de alto.","Hornea 20–25 minutos hasta dorar los bordes.","Corta en porciones, muele pimienta encima y sirve sola o 'a caballo' sobre la pizza."],ilu:{t:"porcion",c:["#E0B45B","#C98B2D","#3A2E2A"]}},
{id:"uy-07",pais:"Uruguay",nombre:"Tortas fritas",desc:"Discos de masa fritos en grasa con su agujero al medio, el clásico de los días de lluvia.",tiempo:60,porciones:6,dificultad:"Fácil",ingredientes:["500 g de harina","100 g de grasa vacuna (más para freír)","1 cdita de sal","Agua tibia cantidad necesaria","Azúcar para espolvorear"],pasos:["Forma una masa tierna con harina, sal, grasa derretida y agua tibia; deja descansar 30 minutos.","Toma bollos, aplánalos en discos de 1 cm.","Hazles el agujero en el centro con el dedo (clave para la cocción pareja).","Fríe en grasa bien caliente hasta dorar ambos lados.","Escurre y espolvorea con azúcar; se comen mirando llover, con mate."],ilu:{t:"pan",c:["#E0B45B","#E8C36A","#FFF6E3"]}},
{id:"uy-08",pais:"Uruguay",nombre:"Ñoquis del 29",desc:"Ñoquis de papa caseros con tuco, que se comen cada 29 con un billete bajo el plato.",tiempo:75,porciones:4,dificultad:"Media",ingredientes:["1 kg de papas","300 g de harina (aproximado)","1 huevo","Nuez moscada y sal","Para el tuco: cebolla, ajo, carne picada o falda, tomate triturado, laurel","Queso rallado"],pasos:["Cocina las papas con cáscara, pélalas y písalas en caliente.","Mezcla con huevo, sal, nuez moscada y la harina justa para una masa suave.","Forma rollos, corta los ñoquis y márcalos con tenedor.","Prepara el tuco: sofríe cebolla y ajo, dora la carne y cocina con el tomate 40 minutos.","Hierve los ñoquis hasta que floten, mezcla con el tuco y sirve con queso rallado (y el billete abajo del plato, por las dudas)."],ilu:{t:"plato",c:["#EFD27A","#C0392B","#F2E3C2"]}},
{id:"uy-09",pais:"Uruguay",nombre:"Postre chajá",desc:"Capas de bizcochuelo, crema, duraznos y merengue seco: el postre creado en Paysandú.",tiempo:90,porciones:8,dificultad:"Alta",ingredientes:["1 bizcochuelo de vainilla","500 ml de crema doble batida con azúcar","1 lata de duraznos en almíbar","200 g de merengues secos triturados","Almíbar de los duraznos para humedecer","Dulce de leche (opcional)"],pasos:["Corta el bizcochuelo en capas y humedécelas con el almíbar de los duraznos.","Bate la crema con azúcar hasta que quede firme.","Arma capas alternando bizcochuelo, crema y duraznos en gajos.","Cubre todo el postre con crema.","Tapiza con el merengue triturado presionando suavemente y refrigera 2 horas antes de servir."],ilu:{t:"copa",c:["#FFF6E3","#E0863B","#F2E3C2"]}},
{id:"uy-10",pais:"Uruguay",nombre:"Martín Fierro",desc:"El postre más simple y querido: queso semiduro con dulce de membrillo en proporciones justas.",tiempo:5,porciones:4,dificultad:"Fácil",ingredientes:["400 g de queso semiduro (colonia o dambo)","400 g de dulce de membrillo"],pasos:["Corta el queso en láminas generosas de 1 cm.","Corta el membrillo del mismo tamaño que el queso.","Apila una lámina de membrillo sobre cada lámina de queso.","Sirve a temperatura ambiente para que el queso exprese su sabor.","Disfruta el contraste: no necesita absolutamente nada más."],ilu:{t:"porcion",c:["#F2E3C2","#B5482F","#E8C36A"]}},
{id:"ve-01",pais:"Venezuela",nombre:"Arepa reina pepiada",desc:"Arepa rellena de pollo con aguacate y mayonesa, la reina indiscutida de las areperas.",tiempo:45,porciones:4,dificultad:"Fácil",ingredientes:["2 tazas de harina de maíz precocida","2,5 tazas de agua tibia","1 cdita de sal","1 pechuga de pollo cocida y deshilachada","1 aguacate grande maduro","1/2 taza de mayonesa","1 cda de jugo de limón","Cilantro picado (opcional)","Pimienta"],pasos:["Mezcla la harina con agua y sal, y amasa hasta lograr una masa suave sin grumos.","Forma discos de 1,5 cm y cocínalos en budare o sartén 7 minutos por lado; termina en horno si quieres que suenen huecas.","Machaca el aguacate con limón y mézclalo con el pollo, la mayonesa y pimienta.","Abre las arepas calientes con un cuchillo sin llegar al borde.","Rellena generosamente con la reina pepiada y sirve de inmediato."],ilu:{t:"arepa",c:["#F2E3C2","#9DBE6E","#E8C36A"]}},
{id:"ve-02",pais:"Venezuela",nombre:"Pabellón criollo",desc:"El plato nacional: carne mechada, caraotas negras, arroz blanco y tajadas de plátano maduro.",tiempo:120,porciones:4,dificultad:"Media",ingredientes:["500 g de falda de res","2 tazas de caraotas negras (remojadas)","2 tazas de arroz","2 plátanos maduros","1 cebolla picada","1 pimentón picado","3 dientes de ajo","2 tomates picados","1 cdita de comino","Aceite, sal y pimienta"],pasos:["Cuece la falda en agua con sal hasta que esté tierna; deshiláchala y reserva el caldo.","Cocina las caraotas en el caldo hasta ablandar y sazónalas con un sofrito.","Sofríe cebolla, ajo, pimentón y tomate; agrega la carne mechada y el comino, y cocina 15 minutos.","Prepara el arroz blanco y fríe las tajadas de maduro hasta dorar.","Sirve los cuatro componentes juntos: ese contraste es el pabellón."],ilu:{t:"plato",c:["#8C4A32","#3A2E2A","#E0A53B"]}},
{id:"ve-03",pais:"Venezuela",nombre:"Hallacas",desc:"El tamal navideño venezolano: masa de maíz con guiso de tres carnes y adornos, envuelta en hoja de plátano.",tiempo:300,porciones:12,dificultad:"Alta",ingredientes:["1 kg de harina de maíz precocida","Caldo de gallina y manteca con onoto para la masa","500 g de res, 500 g de cerdo y 1/2 gallina en cubos pequeños","1 taza de vino tinto o papelón","Cebolla, ajo porro, cebollín, ajo y pimentón para el guiso","Alcaparras, aceitunas, pasas y tiras de pimentón para adornar","Hojas de plátano soasadas","Pabilo (cuerda) para amarrar","Sal, pimienta y comino"],pasos:["Prepara el guiso: cocina las carnes con todos los aliños y el vino hasta que espese; deja enfriar de un día para otro.","Amasa la harina con caldo y manteca coloreada con onoto hasta lograr una masa suave.","Extiende una bola de masa sobre la hoja engrasada, en capa fina.","Coloca guiso y adornos, dobla la hoja, forma el paquete y amárralo con pabilo.","Hierve las hallacas en agua con sal por 1 hora.","Escurre y sirve calientes; en diciembre, repetir es obligatorio."],ilu:{t:"envuelto",c:["#5C7A3E","#E3B23C","#C9A36A"]}},
{id:"ve-04",pais:"Venezuela",nombre:"Cachapas con queso",desc:"Panqueca dulce de maíz tierno doblada sobre queso de mano fundente.",tiempo:35,porciones:4,dificultad:"Fácil",ingredientes:["4 tazas de granos de maíz tierno (jojoto)","3 cdas de azúcar","1/2 cdita de sal","1/4 taza de leche (si hace falta)","2 cdas de harina de maíz (opcional, para dar cuerpo)","400 g de queso de mano o mozzarella fresca","Mantequilla"],pasos:["Licúa el maíz con azúcar y sal hasta obtener una mezcla espesa con textura.","Si queda muy líquida, agrega harina de maíz; si muy espesa, un poco de leche.","Vierte cucharones sobre budare o sartén enmantequillado a fuego medio.","Cocina hasta que burbujee, voltea y dora el otro lado.","Pon el queso sobre la cachapa caliente, dobla por la mitad y sirve con mantequilla."],ilu:{t:"arepa",c:["#EFD27A","#FFF6E3","#E0A53B"]}},
{id:"ve-05",pais:"Venezuela",nombre:"Tequeños",desc:"Dedos de queso envueltos en masa crujiente y fritos: el pasapalo infaltable de toda fiesta venezolana.",tiempo:60,porciones:8,dificultad:"Media",ingredientes:["500 g de harina de trigo","100 g de mantequilla","1 huevo","1 cdita de sal y 1 de azúcar","Agua tibia cantidad necesaria","500 g de queso blanco duro (llanero) en bastones de 1x6 cm","Aceite abundante para freír"],pasos:["Forma una masa lisa con harina, mantequilla, huevo, sal, azúcar y agua; deja reposar 30 minutos.","Estira la masa fina y corta tiras de 2 cm de ancho.","Envuelve cada bastón de queso en espiral, sellando bien los extremos para que no escape el queso.","Fríe en aceite caliente hasta que doren parejo.","Escurre y sirve calientes, con salsa rosada o guasacaca si quieres."],ilu:{t:"brocheta",c:["#E0B45B","#E8C36A","#FFF6E3"]}},
{id:"ve-06",pais:"Venezuela",nombre:"Asado negro",desc:"Muchacho redondo cocido lentamente en caramelo de papelón hasta lograr una salsa oscura y brillante.",tiempo:150,porciones:6,dificultad:"Alta",ingredientes:["1,5 kg de muchacho redondo (corte entero de res)","150 g de papelón rallado o azúcar","1/2 taza de aceite","2 cebollas picadas","1 pimentón picado","6 dientes de ajo","2 tomates picados","1 taza de vino tinto","Laurel, sal y pimienta","Arroz blanco y tajadas para acompañar"],pasos:["Calienta el aceite con el papelón hasta que se forme un caramelo oscuro.","Sella la pieza de carne en ese caramelo por todos lados: debe quedar casi negra.","Agrega los vegetales picados y sofríe alrededor de la carne.","Vierte el vino y agua caliente hasta cubrir a la mitad; cocina tapado a fuego bajo 2 horas, girando.","Corta la carne en rodajas y redúcela en su salsa licuada hasta que brille.","Sirve con arroz blanco y tajadas de plátano."],ilu:{t:"plato",c:["#3A2E2A","#5A3A2A","#E0A53B"]}},
{id:"ve-07",pais:"Venezuela",nombre:"Empanadas venezolanas",desc:"Empanadas fritas de masa de maíz, doraditas y rellenas de carne mechada, queso o cazón.",tiempo:60,porciones:5,dificultad:"Media",ingredientes:["2 tazas de harina de maíz precocida","2,5 tazas de agua","1 cdita de sal y 1 de azúcar","1 cdita de onoto en aceite (para el color)","Relleno a elección: carne mechada, queso blanco rallado o cazón guisado","Aceite abundante para freír"],pasos:["Amasa la harina con agua, sal, azúcar y el aceite con onoto hasta lograr una masa suave y maleable.","Extiende una bola de masa sobre plástico engrasado, en disco delgado.","Coloca el relleno en el centro, dobla con ayuda del plástico y recorta el borde con un bol.","Fríe en aceite bien caliente hasta que infle y dore.","Escurre y sirve con guasacaca o ají dulce."],ilu:{t:"empanada",c:["#EFC94C","#E0A53B","#8C4A32"]}},
{id:"ve-08",pais:"Venezuela",nombre:"Patacón zuliano",desc:"Sándwich maracucho donde el pan son dos plátanos verdes fritos y aplanados, relleno de carne y queso.",tiempo:40,porciones:2,dificultad:"Media",ingredientes:["2 plátanos verdes grandes","300 g de carne mechada o de pollo","100 g de queso de año o gouda rallado","Lechuga y tomate","Salsa rosada y salsa de ajo","Aceite abundante para freír","Sal"],pasos:["Pela los plátanos, córtalos a lo largo por la mitad y fríelos 4 minutos sin dorar del todo.","Aplánalos bien (cada mitad será una 'tapa' del sándwich).","Fríelos de nuevo hasta que queden dorados y crocantes; sala al salir.","Arma el patacón: tapa de plátano, carne caliente, queso, lechuga, tomate y salsas.","Cierra con la otra tapa y sirve con servilletas: es un asunto serio."],ilu:{t:"sandwich",c:["#9DA84E","#8C4A32","#EFC94C"]}},
{id:"ve-09",pais:"Venezuela",nombre:"Quesillo",desc:"El flan venezolano: huevos enteros y leche condensada sobre caramelo, con su textura de 'huequitos'.",tiempo:75,porciones:8,dificultad:"Media",ingredientes:["1 lata de leche condensada","La misma medida de leche entera","5 huevos enteros","1 cdita de vainilla","1 cda de ron (opcional)","1 taza de azúcar para el caramelo"],pasos:["Derrite el azúcar en la quesillera o molde hasta lograr un caramelo dorado y cubre fondo y paredes.","Licúa la leche condensada, la leche, los huevos, la vainilla y el ron.","Vierte la mezcla en el molde acaramelado y tapa (o cubre con papel aluminio).","Cocina a baño de María en horno a 180 °C por 50–60 minutos, hasta que un cuchillo salga limpio.","Enfría por completo en la nevera antes de desmoldar.","Desmolda con confianza y deja que el caramelo bañe el quesillo."],ilu:{t:"porcion",c:["#EFD27A","#C98038","#8C5A2A"]}},
{id:"ve-10",pais:"Venezuela",nombre:"Chicha venezolana",desc:"Bebida cremosa y helada de arroz con leche, canela y vainilla, coronada con leche condensada.",tiempo:40,porciones:4,dificultad:"Fácil",ingredientes:["1 taza de arroz","4 tazas de agua","3 tazas de leche","1 rama de canela","1 cdita de vainilla","1/2 taza de azúcar (al gusto)","Leche condensada y canela molida para servir","Hielo"],pasos:["Cocina el arroz en el agua con la rama de canela hasta que esté muy blando.","Deja entibiar y licúa con la leche, el azúcar y la vainilla hasta que quede totalmente cremosa.","Ajusta el espesor con más leche si hace falta: debe poder beberse con pitillo grueso.","Refrigera hasta que esté bien fría.","Sirve en vasos con hielo, un chorro de leche condensada y canela espolvoreada."],ilu:{t:"vaso",c:["#F2EDE3","#FFF6E3","#C98B5A"]}},
];
